void layernorm(float *out, float *x, float *w, float *b, int n, int d) {
    for (int i = 0; i < n; i++) {
        float mean = 0, var = 0;
        for (int j = 0; j < d; j++) mean += x[i*d+j];
        mean /= d;
        for (int j = 0; j < d; j++) var += (x[i*d+j]-mean)*(x[i*d+j]-mean);
        var /= d;

        float std = 1.0f / sqrtf(var + 1e-5f);
        for (int j = 0; j < d; j++)
            out[i*d+j] = (x[i*d+j]-mean) * std * w[j] + b[j];
    }
}
