int bpe_encode(int *tokens, int n) {
    while (1) {
        int best_rank = 999999, best_pos = -1;
        for (int i = 0; i < n - 1; i++) {
            int rank = mh_get(tokens[i], tokens[i+1]);
            if (rank < best_rank) {
                best_rank = rank;
                best_pos = i;
            }
        }
        if (best_pos < 0) break;
        // Merge tokens[best_pos] and tokens[best_pos+1]
        tokens[best_pos] = 256 + best_rank;
        for (int i

 = best_pos + 1; i < n - 1; i++)
            tokens[i] = tokens[i+1];
        n--;
    }
    return n;
}
